3	type Item = { type: string; cursed?: boolean };
4	
5	type Step = { op: string; items: Item[] };
6	
7	type Scenario = {
8	  customer: { yearsWithMHPCO: number };
9	  steps: Step[];
10	};
11	
12	type StepResult = { premium: number };
13	
14	type ScenarioResult = {
15	  results: StepResult[];
16	};
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
28	const PROCESSING_FEE = 5;
29	
30	const BLOCK_SIZE = 3;
31	const BLOCK_BASE_PREMIUM = 60;
32	
33	const CURSE_SURCHARGE_RATE = 0.5;
34	
35	const countItemsByType = (items: Item[]): Map<string, number> => {
36	  const counts = new Map<string, number>();
37	  for (const item of items) {
38	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	  }
40	  return counts;
41	};
42	
43	const basePremiumForGroup = (type: string, count: number): number =>
44	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
45	
46	const calculateTotalBasePremium = (items: Item[]): number =>
47	  [...countItemsByType(items)].reduce(
48	    (total, [type, count]) => total + basePremiumForGroup(type, count),
49	    0,
50	  );
51	
52	const curseSurchargeForItem = (item: Item): number =>
53	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
54	
55	const calculateCurseSurcharge = (items: Item[]): number =>
56	  items.reduce((total, item) => total + curseSurchargeForItem(item), 0);
57	
58	const quoteStep = (step: Step): StepResult => {
59	  const totalBasePremium = calculateTotalBasePremium(step.items);
60	  const firstInsuranceSurcharge =
61	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
62	  const curseSurcharge = calculateCurseSurcharge(step.items);
63	  return {
64	    premium: Math.ceil(
65	      totalBasePremium + curseSurcharge + firstInsuranceSurcharge +
66	        PROCESSING_FEE,
67	    ),
68	  };
69	};
70	
71	export const processScenario = (scenario: Scenario): ScenarioResult => ({
72	  results: scenario.steps.map(quoteStep),
73	});
