const CURSE_SURCHARGE_RATE = 0.5;

const ENCHANTMENT_SURCHARGE_RATE = 0.3;
const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;

const calculateCurseSurcharge = (items: Item[]): number =>
  items.reduce((total, item) => total + curseSurchargeForItem(item), 0);

const enchantmentSurchargeForItem = (item: Item): number =>
  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
    : 0;

const calculateEnchantmentSurcharge = (items: Item[]): number =>
  items.reduce((total, item) => total + enchantmentSurchargeForItem(item), 0);

